COMMENT ON COLUMN "sys_menu"."alwaysShow" IS '## 是否总是显示根菜单（即使只有一个子菜单）';
COMMENT ON COLUMN "sys_menu"."breadcrumb" IS '## 面包屑导航（true=显示，false=不显示）';
COMMENT ON COLUMN "sys_menu"."component" IS '## 前端组件路径（菜单类型通常需要）';
COMMENT ON COLUMN "sys_menu"."componentName" IS '## 组件名（用于 keep-alive 匹配）';
COMMENT ON COLUMN "sys_menu"."createTime" IS '## 创建时间';
COMMENT ON COLUMN "sys_menu"."creator" IS '## 创建者';
COMMENT ON COLUMN "sys_menu"."deleted" IS '## 是否软删除';
COMMENT ON COLUMN "sys_menu"."icon" IS '## 菜单图标（如：mdi:home）';
COMMENT ON COLUMN "sys_menu"."id" IS '## 菜单ID，主键';
COMMENT ON COLUMN "sys_menu"."keepAlive" IS '## 是否启用缓存（需与 componentName 配合）';
COMMENT ON COLUMN "sys_menu"."parentId" IS '## 父菜单ID（0表示根节点）';
COMMENT ON COLUMN "sys_menu"."path" IS '## 路由地址（目录/菜单通常需要）';
COMMENT ON COLUMN "sys_menu"."permission" IS '## 权限标识（如：system:user:list；按钮类型建议必填）';
COMMENT ON COLUMN "sys_menu"."redirect" IS '## 重定向地址（目录常用于默认跳转）';
COMMENT ON COLUMN "sys_menu"."showInTabs" IS '## 是否在标签页中展示';
COMMENT ON COLUMN "sys_menu"."sort" IS '## 显示顺序（值越小越靠前）';
COMMENT ON COLUMN "sys_menu"."status" IS '## 菜单状态（0=停用 1=正常）';
COMMENT ON COLUMN "sys_menu"."title" IS '## 菜单标题（同一父菜单下唯一）';
COMMENT ON COLUMN "sys_menu"."type" IS '## 菜单类型（1=目录 2=菜单 3=按钮）';
COMMENT ON COLUMN "sys_menu"."updateTime" IS '## 更新时间';
COMMENT ON COLUMN "sys_menu"."updater" IS '## 更新者';
COMMENT ON COLUMN "sys_menu"."visible" IS '## 是否在侧边栏可见';

